local repo = "https://raw.githubusercontent.com/deividcomsono/Obsidian/main/"
local Library = loadstring(game:HttpGet(repo .. "Library.lua"))()
local ThemeManager = loadstring(game:HttpGet(repo .. "addons/ThemeManager.lua"))()

local moduleUrl = "https://raw.githubusercontent.com/checkurasshole/INK/main/KaijuAlphaModule"
local FlyModule = loadstring(game:HttpGet(moduleUrl))()

FlyModule.init()

local Players = game:GetService("Players")
local localPlayer = Players.LocalPlayer

local Window = Library:CreateWindow({
    Title            = "COMBOWICK",
    Icon             = 6031071057,
    NotifySide       = "Right",
    ShowCustomCursor = false,
    Size             = UDim2.new(0, 560, 0, 500),
})

local Tabs = {
    Main = Window:AddTab("Main", "star"),
}

local Left  = Tabs.Main:AddLeftGroupbox("Fly")
local Right = Tabs.Main:AddRightGroupbox("生成与选项")

Left:AddToggle("FlyEnabled", {
    Text    = "启用飞行  [F]",
    Default = false,
    Callback = function(v)
        if v then FlyModule.startFly() else FlyModule.stopFly() end
    end,
})

Left:AddDropdown("FlyMode", {
    Text    = "飞行模式",
    Default = "PC",
    Values  = { "PC", "Mobile" },
    Callback = function(v)
        FlyModule.Config.FlyMode = v
        if FlyModule.Config.FlyEnabled then FlyModule.startFly() end
    end,
})

Left:AddSlider("FlySpeed", {
    Text     = "飞行速度",
    Default  = 22, Min = 5, Max = 50, Rounding = 0,
    Callback = function(v)
        FlyModule.Config.Speed = v
        local hum = FlyModule.getHum()
        if hum and FlyModule.Config.FlyEnabled then hum.WalkSpeed = v end
    end,
})

Left:AddToggle("AccelEnabled", {
    Text    = "加速度  （仅限 PC）",
    Default = true,
    Callback = function(v) FlyModule.Config.Acceleration = v end,
})

Left:AddSlider("MaxAccelMult", {
    Text    = "最大加速度倍率",
    Default = 1.5, Min = 1.0, Max = 2.0, Rounding = 1,
    Callback = function(v) FlyModule.Config.MaxAccel = v end,
})

local kaijuLabel = Right:AddLabel("Kaiju：检测中...")

local function refreshKaijuLabel()
    local name = FlyModule.getSelectedKaiju()
    kaijuLabel:SetText("Kaiju: " .. (name ~= "" and name or "None Detected"))
end

refreshKaijuLabel()

local ls = localPlayer:FindFirstChild("leaderstats")
local kv = ls and ls:FindFirstChild("Kaiju")
if kv then
    kv.Changed:Connect(refreshKaijuLabel)
end

Right:AddButton("生成当前 Kaiju", function()
    FlyModule.fireSpawn()
end)

Right:AddToggle("AutoSpawnToggle", {
    Text    = "无限技能 / 无限生命",
    Default = true,
    Callback = function(v) FlyModule.Config.AutoSpawn = v end,
})

Right:AddDivider()

Right:AddButton("Unload", function()
    FlyModule.stopFly()
    FlyModule.stopFly2()
    Library:Unload()
end)

ThemeManager:SetLibrary(Library)
ThemeManager:SetFolder("KaijuScript")
ThemeManager:ApplyToTab(Tabs.Main)

